<?php
if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Sync { const META_LAST_SYNC_AT = 'tct_last_sync_at_utc'; const META_LAST_SYNC_STATUS = 'tct_last_sync_status'; const META_LABELS_CACHE = 'tct_labels_cache'; const META_LABELS_CACHE_AT = 'tct_labels_cache_at_utc'; public static function sync_labels( $user_id ) { $token = TCT_OAuth::get_token( $user_id ); if ( empty( $token ) ) { return new WP_Error( 'tct_no_token', 'User is not connected to Todoist.' ); } $resp = TCT_Todoist_API::get_labels( $token ); if ( is_wp_error( $resp ) ) { return $resp; } $labels = array(); if ( isset( $resp['labels'] ) && is_array( $resp['labels'] ) ) { $labels = $resp['labels']; } update_user_meta( $user_id, self::META_LABELS_CACHE, wp_json_encode( $labels ) ); update_user_meta( $user_id, self::META_LABELS_CACHE_AT, current_time( 'mysql', true ) ); return $labels; } public static function get_cached_labels( $user_id ) { $raw = get_user_meta( $user_id, self::META_LABELS_CACHE, true ); if ( ! $raw || ! is_string( $raw ) ) { return array(); } $json = json_decode( $raw, true ); if ( ! is_array( $json ) ) { return array(); } return $json; } public static function sync_user( $user_id, $is_manual = false ) { global $wpdb; $token = TCT_OAuth::get_token( $user_id ); if ( empty( $token ) ) { return new WP_Error( 'tct_no_token', 'User is not connected to Todoist.' ); } $horizon_days = TCT_Admin::get_sync_horizon_days(); $now_utc = new DateTimeImmutable( 'now', new DateTimeZone( 'UTC' ) ); $since_utc = $now_utc->sub( new DateInterval( 'P' . (int) $horizon_days . 'D' ) ); $since_param = TCT_Utils::format_todoist_since_until( $since_utc ); $until_param = TCT_Utils::format_todoist_since_until( $now_utc ); $since_mysql = TCT_Utils::dt_to_mysql_utc( $since_utc ); $until_mysql = TCT_Utils::dt_to_mysql_utc( $now_utc ); $completions_table = TCT_DB::table_completions(); $goals_table = TCT_DB::table_goals(); $wpdb->query( $wpdb->prepare( "DELETE FROM {$completions_table}
                 WHERE user_id = %d
                   AND completed_at >= %s
                   AND (source = 'todoist' OR source = '' OR source IS NULL)", $user_id, $since_mysql ) ); $goal_rows = $wpdb->get_results( $wpdb->prepare( "SELECT id, label_name, tracking_mode
                 FROM {$goals_table}
                 WHERE user_id = %d
                   AND is_tracked = 1
                   AND label_name IS NOT NULL AND label_name <> ''
                   AND tracking_mode <> 'manual'
                   AND (wake_time_enabled IS NULL OR wake_time_enabled = 0)
                   AND (goal_type IS NULL OR goal_type = '' OR goal_type = 'positive')", $user_id ), ARRAY_A ); $label_to_goal_id = array(); if ( is_array( $goal_rows ) ) { foreach ( $goal_rows as $g ) { $gid = isset( $g['id'] ) ? (int) $g['id'] : 0; $ln = isset( $g['label_name'] ) ? sanitize_text_field( (string) $g['label_name'] ) : ''; if ( $gid > 0 && '' !== $ln ) { $label_to_goal_id[ strtolower( $ln ) ] = $gid; } } } $limit = 200; $offset = 0; $total_items = 0; $total_rows_inserted = 0; $total_rows_suppressed = 0; $created_at = current_time( 'mysql', true ); while ( true ) { $resp = TCT_Todoist_API::get_completed_items( $token, array( 'since' => $since_param, 'until' => $until_param, 'limit' => $limit, 'offset' => $offset, 'annotate_items' => 'true', ) ); if ( is_wp_error( $resp ) ) { update_user_meta( $user_id, self::META_LAST_SYNC_AT, current_time( 'mysql', true ) ); update_user_meta( $user_id, self::META_LAST_SYNC_STATUS, 'error: ' . $resp->get_error_message() ); return $resp; } $items = isset( $resp['items'] ) && is_array( $resp['items'] ) ? $resp['items'] : array(); if ( empty( $items ) ) { break; } $total_items += count( $items ); $rows = array(); foreach ( $items as $item ) { if ( empty( $item['id'] ) || empty( $item['task_id'] ) || empty( $item['completed_at'] ) ) { continue; } $completed_at_mysql = TCT_Utils::iso_to_mysql_utc( (string) $item['completed_at'] ); if ( null === $completed_at_mysql ) { continue; } $content = isset( $item['content'] ) ? (string) $item['content'] : ''; $labels = array(); if ( isset( $item['item_object'] ) && is_array( $item['item_object'] ) && isset( $item['item_object']['labels'] ) && is_array( $item['item_object']['labels'] ) ) { $labels = $item['item_object']['labels']; } if ( empty( $labels ) ) { continue; } $todoist_completed_id = sanitize_text_field( (string) $item['id'] ); $todoist_task_id = sanitize_text_field( (string) $item['task_id'] ); foreach ( $labels as $label_name_raw ) { $label_name = sanitize_text_field( (string) $label_name_raw ); if ( '' === $label_name ) { continue; } $key = strtolower( $label_name ); if ( ! isset( $label_to_goal_id[ $key ] ) ) { continue; } $goal_id = (int) $label_to_goal_id[ $key ]; if ( $goal_id <= 0 ) { continue; } if ( self::has_manual_completion_nearby( $user_id, $goal_id, $completed_at_mysql ) ) { $total_rows_suppressed++; continue; } $rows[] = array( 'user_id' => (int) $user_id, 'goal_id' => (int) $goal_id, 'source' => 'todoist', 'source_ref' => $todoist_completed_id . ':' . (string) $goal_id, 'todoist_completed_id' => $todoist_completed_id, 'todoist_task_id' => $todoist_task_id, 'label_name' => $label_name, 'task_content' => wp_kses_post( $content ), 'note' => '', 'completed_at' => $completed_at_mysql, 'created_at' => $created_at, ); } } if ( ! empty( $rows ) ) { $inserted = self::bulk_upsert_completions( $rows ); if ( is_wp_error( $inserted ) ) { update_user_meta( $user_id, self::META_LAST_SYNC_AT, current_time( 'mysql', true ) ); update_user_meta( $user_id, self::META_LAST_SYNC_STATUS, 'error: ' . $inserted->get_error_message() ); return $inserted; } $total_rows_inserted += (int) $inserted; } $offset += $limit; if ( $offset > 200000 ) { break; } } update_user_meta( $user_id, self::META_LAST_SYNC_AT, current_time( 'mysql', true ) ); update_user_meta( $user_id, self::META_LAST_SYNC_STATUS, 'ok: ' . $total_items . ' completed items processed; ' . $total_rows_inserted . ' events inserted; ' . $total_rows_suppressed . ' suppressed' ); TCT_Ledger::reconcile_user( $user_id, $since_mysql, $until_mysql ); return array( 'completed_items_processed' => $total_items, 'events_inserted' => $total_rows_inserted, 'events_suppressed' => $total_rows_suppressed, 'since_utc' => $since_param, 'until_utc' => $until_param, ); } private static function has_manual_completion_nearby( $user_id, $goal_id, $completed_at_utc_mysql ) { global $wpdb; $user_id = (int) $user_id; $goal_id = (int) $goal_id; if ( $user_id <= 0 || $goal_id <= 0 ) { return false; } $table = TCT_DB::table_completions(); $dt = null; try { $dt = new DateTimeImmutable( (string) $completed_at_utc_mysql, new DateTimeZone( 'UTC' ) ); } catch ( Exception $e ) { return false; } $window_minutes = 10; $start = $dt->sub( new DateInterval( 'PT' . (int) $window_minutes . 'M' ) ); $end = $dt->add( new DateInterval( 'PT' . (int) $window_minutes . 'M' ) ); $start_mysql = TCT_Utils::dt_to_mysql_utc( $start ); $end_mysql = TCT_Utils::dt_to_mysql_utc( $end ); $found = (int) $wpdb->get_var( $wpdb->prepare( "SELECT COUNT(*) FROM {$table}
                 WHERE user_id = %d
                   AND goal_id = %d
                   AND source = 'manual'
                   AND completed_at >= %s AND completed_at <= %s", $user_id, $goal_id, $start_mysql, $end_mysql ) ); return $found > 0; } private static function bulk_upsert_completions( $rows ) { global $wpdb; $table = TCT_DB::table_completions(); $columns = array( 'user_id', 'goal_id', 'source', 'source_ref', 'todoist_completed_id', 'todoist_task_id', 'label_name', 'task_content', 'note', 'completed_at', 'created_at', ); $chunk_size = 200; $inserted_total = 0; $chunks = array_chunk( $rows, $chunk_size ); foreach ( $chunks as $chunk ) { $placeholders = array(); $values = array(); foreach ( $chunk as $row ) { $placeholders[] = "(%d,%d,%s,%s,%s,%s,%s,%s,%s,%s,%s)"; $values[] = (int) $row['user_id']; $values[] = (int) $row['goal_id']; $values[] = (string) $row['source']; $values[] = (string) $row['source_ref']; $values[] = (string) $row['todoist_completed_id']; $values[] = (string) $row['todoist_task_id']; $values[] = (string) $row['label_name']; $values[] = (string) $row['task_content']; $values[] = (string) $row['note']; $values[] = (string) $row['completed_at']; $values[] = (string) $row['created_at']; } $sql = "INSERT INTO {$table} (" . implode( ',', $columns ) . ") VALUES " . implode( ',', $placeholders ) . "
                ON DUPLICATE KEY UPDATE
                    todoist_completed_id = VALUES(todoist_completed_id),
                    todoist_task_id = VALUES(todoist_task_id),
                    label_name = VALUES(label_name),
                    task_content = VALUES(task_content),
                    note = VALUES(note),
                    completed_at = VALUES(completed_at),
                    created_at = VALUES(created_at)"; $prepared = $wpdb->prepare( $sql, $values ); $result = $wpdb->query( $prepared ); if ( false === $result ) { return new WP_Error( 'tct_db_insert_error', 'Database error while inserting completion events.' ); } $inserted_total += count( $chunk ); } return $inserted_total; } public static function delete_user_data( $user_id ) { global $wpdb; $completions = TCT_DB::table_completions(); $goals = TCT_DB::table_goals(); $domains = TCT_DB::table_domains(); $roles = TCT_DB::table_roles(); $ledger = TCT_DB::table_ledger(); $wpdb->query( $wpdb->prepare( "DELETE FROM {$completions} WHERE user_id = %d", $user_id ) ); $wpdb->query( $wpdb->prepare( "DELETE FROM {$domains} WHERE user_id = %d", $user_id ) ); $wpdb->query( $wpdb->prepare( "DELETE FROM {$roles} WHERE user_id = %d", $user_id ) ); $wpdb->query( $wpdb->prepare( "DELETE FROM {$goals} WHERE user_id = %d", $user_id ) ); $wpdb->query( $wpdb->prepare( "DELETE FROM {$ledger} WHERE user_id = %d", $user_id ) ); delete_user_meta( $user_id, TCT_Ledger::META_POINTS_STARTED_AT ); delete_user_meta( $user_id, 'tct_reward_active' ); delete_user_meta( $user_id, 'tct_reward_hof' ); } } 
